        description: "\u0935\u093f\u091c\u093c\u0941\u0905\u0932 \u092a\u093e\u0907\u092a\u0932\u093e\u0907\u0928 \u092c\u0928\u093e\u090f\u0901 \u091c\u0939\u093e\u0901 \u0915\u0908 \u090f\u091c\u0947\u0902\u091f\u094d\u0938 \u091c\u091f\u093f\u0932 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092a\u0930 \u0938\u0939\u092f\u094b\u0917 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u090f\u0915 \u090f\u091c\u0947\u0902\u091f \u0915\u093e \u0906\u0909\u091f\u092a\u0941\u091f \u0905\u0917\u0932\u0947 \u092e\u0947\u0902 \u091c\u093e\u0924\u093e \u0939\u0948 \u2014 \u0915\u094b\u0908 \u0917\u094d\u0932\u0942 \u0915\u094b\u0921 \u0928\u0939\u0940\u0902, \u0915\u094b\u0908 \u092e\u0948\u0928\u0941\u0905\u0932 \u0915\u0926\u092e \u0928\u0939\u0940\u0902, \u0906\u092a \u091c\u094b \u0911\u0930\u094d\u0915\u0947\u0938\u094d\u091f\u094d\u0930\u0947\u091f \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u0909\u0938 \u092a\u0930 \u0915\u094b\u0908 \u0938\u0940\u092e\u093e \u0928\u0939\u0940\u0902\u0964",
