        cta: "\u0905\u092a\u0928\u0947 \u0915\u0928\u0947\u0915\u094d\u0936\u0928 \u0938\u0941\u0930\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0947\u0902"
