      ctaTitle: "\u0905\u092a\u0928\u0947 \u0916\u0941\u0926 \u0915\u0947 \u090f\u091c\u0947\u0902\u091f \u092c\u0928\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0924\u0948\u092f\u093e\u0930?",
      ctaDescription: "Personas \u0921\u093e\u0909\u0928\u0932\u094b\u0921 \u0915\u0930\u0947\u0902 \u0914\u0930 \u0938\u094d\u0935\u093e\u092f\u0924\u094d\u0924 \u090f\u091c\u0947\u0902\u091f \u092c\u0928\u093e\u090f\u0902 \u091c\u094b \u0906\u092a\u0915\u0947 \u091f\u0942\u0932\u094d\u0938 \u0938\u0947 \u091c\u0941\u0921\u093c\u0924\u0947 \u0939\u0948\u0902, \u0906\u092a\u0915\u0947 \u0928\u093f\u092f\u092e\u094b\u0902 \u0915\u093e \u092a\u093e\u0932\u0928 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0906\u092a\u0915\u0947 \u0936\u0947\u0921\u094d\u092f\u0942\u0932 \u092a\u0930 \u091a\u0932\u0924\u0947 \u0939\u0948\u0902\u0964",
